# Input parameters from Rewst
$user_id = "{{ CTX.user_id }}"

# Create Object for POST Back to Rewst Later
$PS_Results = New-Object -TypeName psobject

# Check if the user_id is a valid SID
$SIDRegex = "^S-\d-\d+-(\d+-){1,14}\d+$"

if ($user_id -match $SIDRegex) {
    # If it's a valid SID, use Get-ADUser with SID
    try {
        $User = Get-ADUser -Identity $user_id
        $Groups = @($User | Get-ADPrincipalGroupMembership | Select-Object -ExpandProperty Name)
        $PS_Results | Add-Member -MemberType NoteProperty -Name "Groups" -Value $Groups
        $PS_Results | Add-Member -MemberType NoteProperty -Name "Match-Count" -Value $Groups.Count
        $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $true
    } catch {
        $PS_Results | Add-Member -MemberType NoteProperty -Name "Error" -Value "Failed to list groups for this SID"
        $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $false
    }
} else {
    # If it's not a SID, handle it as a UserPrincipalName filter
    try {
        $User = Get-ADUser -Filter "UserPrincipalName -like '$user_id@*'"
        
        # Ensure the found account matches the provided user ID
        if (($User.UserPrincipalName -split '@')[0] -eq $user_id) {
            $Groups = @($User | Get-ADPrincipalGroupMembership | Select-Object -ExpandProperty Name)
            $PS_Results | Add-Member -MemberType NoteProperty -Name "Groups" -Value $Groups
            $PS_Results | Add-Member -MemberType NoteProperty -Name "Match-Count" -Value $Groups.Count
            $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $true
        } else {
            $PS_Results | Add-Member -MemberType NoteProperty -Name "Error" -Value "No exact match for user ID"
            $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $false
        }
    } catch {
        $PS_Results | Add-Member -MemberType NoteProperty -Name "Error" -Value "Failed to list groups for this user"
        $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $false
    }
}

# Post results back to Rewst
$postData = $PS_Results | ConvertTo-Json -Depth 10
Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'

Import-Module ActiveDirectory

$PS_Results = @()  # Create an array to hold results

try {
    $serverlist = Get-ADComputer -Filter 'OperatingSystem -like "*server*" -and Enabled -eq $true' -Properties Name, OperatingSystem, OperatingSystemVersion, IPv4Address |
                  Sort-Object OperatingSystem |
                  Select-Object Name, OperatingSystem, OperatingSystemVersion, IPv4Address

    foreach ($server in $serverlist) {
        try {
            # Add Server Info
            $PS_Results += [PSCustomObject]@{
                server            = $server.Name
                operating_system  = $server.OperatingSystem
                version           = $server.OperatingSystemVersion
                ip                = $server.IPv4Address
            }
        } catch {
            Write-Output "No access to $($server.Name)"
        }
    }
} catch {
    Write-Output "Failed to find servers: $_"
}

# Convert the collected results to JSON and ensure it's always an array
try {
    if ($PS_Results.Count -gt 0) {
        # Convert to JSON, ensuring array format
        $postData = @($PS_Results) | ConvertTo-Json -Depth 10 -Compress
        $encodedPostData = [System.Text.Encoding]::UTF8.GetBytes($postData)

        # Ensure valid headers
        Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $encodedPostData -ContentType 'application/json; charset=utf-8'
    } else {
        $postData = "Unable to find Domain Servers."
        $encodedPostData = [System.Text.Encoding]::UTF8.GetBytes($postData)

        # Ensure valid headers
        Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $encodedPostData -ContentType 'application/json; charset=utf-8'
    }
} catch {
    Write-Output "Failed to send data to rewst"
}

{%- set data_ns = namespace(log = [], status = 0) -%}
{%- for key, value in CTX()|items -%}
    {%- if key.startswith("log_") -%}
        {%- set entry = value %}
        {%- do entry.update({"task": key|replace("log_", "")}) -%}
        {%- do data_ns.log.append(entry) -%}
    {%- endif -%}
{%- endfor -%}

{%- macro status_code() -%}
    {%- set data_ns.status = [entry.status_code|d(0) for entry in data_ns.log]|sort(true)|first
    or 2000 -%}
    {%- if data_ns.status  > 1000 and data_ns.status  < 2000 -%}
        {%- set data_ns.status = 1001 -%}
    {%- elif data_ns.status > 2000 -%}
        {%- set data_ns.status = 2000 -%}
    {%- endif -%}
    {{- data_ns.status -}}
{%- endmacro -%}

{%- macro succeeded() -%}
    {{- data_ns.status < 2000  -}}
{%- endmacro -%}

{%- macro data() -%}
    {%- set data = {} -%}
    {%- for entry in data_ns.log -%}
        {%- if entry.data|d({}) or {} != {} -%}
            {%- do data.update(entry.data) -%}
        {%- endif -%}
    {%- endfor -%}
    {{- data or None -}}
{%- endmacro -%}

{%- macro warnings() -%}
{{-
    [
        entry for entry in data_ns.log
            if entry.status_code|d(0) > 1000 and entry.status_code|d(0) < 2000
    ]
-}}
{%- endmacro -%}

{%- macro errors() -%}
{{-
    [
        entry for entry in data_ns.log
            if entry.status_code|d(0) >= 2000
    ]
-}}
{%- endmacro -%}

{{-
    {
        "status_code": status_code(),
        "succeeded": succeeded(),
        "data": data(),
        "errors": errors(),
        "warnings": warnings(),
        "entries": data_ns.log
    }
-}}

$attribute = "{{ CTX.attribute }}"

$PS_Results = New-Object -TypeName psobject
$PS_Results | Add-Member -MemberType NoteProperty -Name "Action" -Value "Get List of Unique Values of AD attribute $attribute for all Users."

try {
    $value_list = [array](Get-ADUser -Filter * -Properties * | Select-Object -Unique $attribute | Where-Object {$_.$attribute -ne $null})
    if ($attribute -eq "HomeDirectory") {
            $unique_home_dirs = [array]($value_list.HomeDirectory.tolower() | Split-Path | Sort-Object | Unique)
            $value_list = New-Object -TypeName psobject 
            $value_list | Add-Member -MemberType NoteProperty -Name "HomeDirectory" -Value $unique_home_dirs
        } 
    $PS_Results | Add-Member -Membertype NoteProperty -Name "Values" -Value $value_list 

    if ($value_list.count -eq 0) {
        $PS_Results | Add-Member -Membertype NoteProperty -Name "Error" -Value "No values found for the $attribute attribute"
    }
} catch {
    $PS_Results | Add-Member -Membertype NoteProperty -Name "Error" -Value "Error retrieving attribute data for $attribute"
}

# Post results back to Rewst
$postData = $PS_Results | ConvertTo-Json
Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json'

### Check if Powershell version above 5.1 ###

if ($PSVersionTable.PSVersion.Major -lt 5) {
    $PS_Results = "$env:computername is running PS version that is less than 5.1 (detected $($PSVersionTable.PSVersion)), script cannot continue. Please upgrade."
    $postData = $PS_Results | ConvertTo-Json
    Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'
    exit
}

### Create object for results ###

$PS_Results = [System.Collections.Generic.List[object]]::new()

### Define some Variables as required ###

$username = "{{ CTX.user_identifier|d }}"
$userPrincipalName = "{{- CTX.user_identifier|d~"@"~CTX.email_domain|d -}}"

### Confirm that the user exists on-prem and add the user info to results, filtering what we return ###

try {
    $userInformation = Get-ADUser $username | Select-Object GivenName, Surname, UserPrincipalName, Enabled, SamAccountName, @{Label = 'SID'; Expression = { $_.SID.AccountDomainSid.Value } }, DistinguishedName, Name, ObjectGUID
    $PS_Results.Add("Failure: User $($userInformation.UserPrincipalName) found.")
}
catch {
    try{
        $userInformation = Get-ADUser -Filter 'UserPrincipalName -like $userPrincipalName'
    }
    catch{}
    if ($userInformation){
        $PS_Results.Add("Failure: User $($userInformation.UserPrincipalName) found.")
    }
    else{
        $PS_Results.Add("Success: User $userPrincipalName not found.")
    }
}

### Send all the data back to RewstyRewst ###

$postData = $PS_Results | ConvertTo-Json
Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'

# Input parameters
$user_sid = "{{ CTX.user_id }}" 

# Create Object for POST Back to Rewst Later
$PS_Results = New-Object -TypeName psobject

# Attempt to retrieve the user object
try {
    # Try to get the user using Get-ADUser
    $User = Get-ADUser -Identity $user_sid -Properties UserPrincipalName
    if ($User -and $User.UserPrincipalName) {
        # Add UPN to the results if found
        $PS_Results | Add-Member -MemberType NoteProperty -Name "upn" -Value $User.UserPrincipalName
        $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $true
    } else {
        # If Get-ADUser fails or does not return UPN, fall back to Get-ADObject
        $ADObject = Get-ADObject -Identity $user_sid -Properties UserPrincipalName
        if ($ADObject -and $ADObject.UserPrincipalName) {
            $PS_Results | Add-Member -MemberType NoteProperty -Name "upn" -Value $ADObject.UserPrincipalName
            $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $true
        } else {
            # No UPN found
            $PS_Results | Add-Member -MemberType NoteProperty -Name "Error" -Value "No UPN found for the provided SID"
            $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $false
        }
    }
} catch {
    # Log any errors
    $ErrorMessage = $_.Exception.Message
    $PS_Results | Add-Member -MemberType NoteProperty -Name "Error" -Value "Failed to retrieve user. Error: $ErrorMessage"
    $PS_Results | Add-Member -MemberType NoteProperty -Name "success" -Value $false
}

# Post results back to Rewst
$postData = $PS_Results | ConvertTo-Json -Depth 10
Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'

$selectedShareServer = "{{ CTX.specfied_share_server or "" }}"
$computerName = if (![string]::IsNullOrEmpty($selectedShareServer)) { $selectedShareServer } else { $env:COMPUTERNAME }

# Validate the target server (specified or local)
if (![string]::IsNullOrEmpty($selectedShareServer)) {
    if (-not (Test-Connection -ComputerName $selectedShareServer -Count 1 -Quiet)) {
        $PS_Results = "The specified server '$selectedShareServer' is not reachable."
        $postData = $PS_Results
        Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'
        exit
    }
}

# Attempt to list shared folders on the target server
try {
    $shares = Get-SmbShare -CimSession $computerName | Where-Object { $_.Name -notmatch "^\$" }
    if ($shares.Count -eq 0) {
        Write-Output "No shared folders found on the server: $computerName"
        exit
    }
} catch {
    Write-Output "Failed to retrieve shared folders on the server: $computerName. Error: $($_.Exception.Message)"
    exit
}

# Collect shared folder details
$PS_Results = @()
foreach ($share in $shares) {
    $PS_Results += [PSCustomObject]@{
        Share   = $share.Name
        UNCPath = "\\$computerName\$($share.Name)"
        Path    = $share.Path
    }
}

# Output or process the results
if ($PS_Results.Count -gt 0) {
    $postData = $PS_Results | ConvertTo-Json -Depth 10
    $postData = [System.Text.Encoding]::UTF8.GetBytes($postData)
    Invoke-RestMethod -Method 'Post' -Uri $post_url -Body $postData -ContentType 'application/json; charset=utf-8'
} else {
    Write-Output "No shared folders found on the server: $computerName"
}

