{% set mylocation = [] %}
{# itterate the results and conditionally return Name - City, State; this should be a more friendly dropdown #}
{% for x in CTX.company_locations %}
    {% if x.stateReference.identifier is defined and x.city is defined %}
        {# creating friendly name variable f_name, to use this you need to change the form to use f_name as the label variable, please note id is not used, but I am adding it as th3e workflow / sub workflows should be updated to use the id vs the name #}
        {% set temploc = {"id":x.id, "f_name":(x.name+" - "+x.city+", "+x.stateReference.identifier), "label":x.name} %}
        {% set temp = mylocation.append(temploc) %}
    {# adding this logic for if the name is not null but city / state are missing #}
    {% elif not (x.name == '') %}
        {% set temploc = {"id":x.id, "f_name":x.name, "label":x.name} %}
        {% set temp = mylocation.append(temploc) %}
    {% endif %}
{% endfor %}
{{- mylocation | sort(attribute='label')-}}

