{# Username options generation logic for AAD Username Override Field, updated 03/15/23 D.Hayes #}
{# Org variable username_format can be set to and of the format options below '_' is equal to a '.' #}
{%- set first_name = CTX.first_name | replace(' ','') | trim -%}
{%- set first_name = (first_name | lower) if CTX.lower_case else first_name -%}
{%- set last_name = CTX.last_name | replace(' ','') | trim -%}
{%- set last_name = last_name | lower if CTX.lower_case else last_name -%}
{%- set my_options = [] -%}
{# building the format options (note that these values are required input so no validation is being performed on its existance) #}
{%- set formats = [
    {"format":"first_last","username":first_name+'.'+last_name},
    {"format":"firstlast","username":first_name+last_name},
    {"format":"first_l","username":first_name+'.'+last_name[:1]},
    {"format":"firstl","username":first_name+last_name[:1]},
    {"format":"first","username":first_name},
    {"format":"f_last","username":first_name[:1]+'.'+last_name},
    {"format":"flast","username":first_name[:1]+last_name},
    {"format":"fl","username":first_name[:1]+last_name[:1]},
    {"format":"last_first","username":last_name+'.'+first_name},
    {"format":"lastfirst","username":last_name+first_name},
    {"format":"last_f","username":last_name+'.'+first_name[:1]},
    {"format":"lastf","username":last_name+first_name[:1]},
    {"format":"last","username":last_name},
    {"format":"l_first","username":last_name[:1]+'.'+first_name},
    {"format":"lfirst","username":last_name[:1]+first_name}] -%}
{# building middle name format options #}
{%- if CTX.middle_name -%}
    {%- set middle_name = CTX.middle_name | replace(' ','') | trim -%}
    {%- set middle_name = middle_name | lower if CTX.lower_case else middle_name -%}
    {%- set tmp = formats.append({"format":"first_middle_last","username":first_name+'.'+middle_name+'.'+last_name}) -%}
    {%- set tmp = formats.append({"format":"first_middlelast","username":first_name+'.'+middle_name+last_name}) -%}
    {%- set tmp = formats.append({"format":"first_m_last","username":first_name+'.'+middle_name[:1]+'.'+last_name}) -%}
    {%- set tmp = formats.append({"format":"firstmlast","username":first_name+middle_name[:1]+last_name}) -%}
    {%- set tmp = formats.append({"format":"fmlast","username":first_name[:1]+middle_name[:1]+last_name}) -%}
    {%- set tmp = formats.append({"format":"fml","username":first_name[:1]+middle_name[:1]+last_name[:1]}) -%}
{%- endif -%}
{# Checking to see that default format is defined #}
{%- if (ORG.VARIABLES.aad_override_username_format is defined) and (ORG.VARIABLES.aad_override_username_format != "none") -%}
    {%- for item in formats -%}
        {# matching default format to its result #}
        {%- if item.format == ORG.VARIABLES.aad_override_username_format -%}
            {% if item.username|length <= 20 %}
                {%- set tmp = my_options.append({"username":item.username,"is_default":1}) -%}
            {% else %}
                {%- set tmp = my_options.append({"username":"Name too long","is_default":1}) -%}
            {% endif %}
        {%- else -%}
            {% if item.username|length <= 20 %}
                {%- set tmp = my_options.append({"username":item.username,"is_default":0}) -%}
            {% endif %}
        {%- endif -%}
    {%- endfor -%}
{%- else -%}
    {%- for item in formats -%}
        {# building list with out default #}
        {% if item.username|length <= 20 %}
            {%- set tmp = my_options.append({"username":item.username,"is_default":0}) -%}
        {% endif %}
    {%- endfor -%}
{%- endif -%}
{#{{- [u_name for u_name in my_options if u_name.username|length <= 20] -}}#}
{{- my_options -}}

{{
	{
		"message":"Username generated using AAD Override",
		"status_code": 1000
	}
}}

