{%- macro data() -%}
    {%- set data = {} -%}
    {%- for entry in data_ns.log -%}
        {%- if entry.data|d({}) or {} != {} -%}
            {%- do data.update(entry.data) -%}
        {%- endif -%}
    {%- endfor -%}
    {{- data or None -}}
{%- endmacro -%}

{%- macro warnings() -%}
{{-
    [
