        {% set temploc = {"id":x.id, "f_name":(x.name+" - "+x.city+", "+x.state), "label":x.name} %}
        {% set temp = mylocation.append(temploc) %}
    {# adding this logic for if the name is not null but city / state are missing #}
    {% elif not (x.name == '') %}
        {% set temploc = {"id":x.id, "f_name":x.name, "label":x.name} %}
        {% set temp = mylocation.append(temploc) %}
    {% endif %}
{% endfor %}
